```class Solution {
public:
    string reverseStr(string s, int k) {
        int len = s.length();
        int mod = len % 2;
        string result = "";
        for (int i = 0; i < len; i++) {
            if (i + k <= len && i + k - mod <= len) {
                result += s[i];
            } else if (i + k <= len) {
                result += s[i + k - mod];
            }
        }
        return result;
    }
};
